// Catalog Page
function CatalogPage({
  animes,
  onAnimeClick,
  hasMore,
  loadMore,
  loading,
  total,
}: {
  animes: AnimeListItem[];
  onAnimeClick: (anime: AnimeListItem) => void;
  hasMore: boolean;
  loadMore: () => void;
  loading: boolean;
  total: number;
}) {
  const observerRef = useRef<IntersectionObserver | null>(null);
  const loadMoreRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    observerRef.current = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && hasMore && !loading) {
          loadMore();
        }
      },
      { threshold: 0.1 }
    );

    if (loadMoreRef.current) {
      observerRef.current.observe(loadMoreRef.current);
    }

    return () => {
      if (observerRef.current) {
        observerRef.current.disconnect();
      }
    };
  }, [hasMore, loadMore, loading]);

  return (
    <section className="pt-6 pb-20 md:pb-8">
      <div className="px-4 sm:px-6 lg:px-12 mb-6">
        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
          <div>
            <h1 className="text-2xl md:text-3xl font-bold text-white mb-1">Catalogue</h1>
            <p className="text-gray-400 text-sm">{total.toLocaleString()} animes disponibles</p>
          </div>
        </div>
      </div>

      <div className="px-4 sm:px-6 lg:px-12">
        <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 lg:grid-cols-6 xl:grid-cols-7 2xl:grid-cols-8 gap-3 md:gap-4">
          {animes.map((anime, index) => (
            <AnimeCard key={anime.id} anime={anime} onClick={() => onAnimeClick(anime)} index={index} />
          ))}
        </div>

        <div ref={loadMoreRef} className="flex justify-center py-8">
          {loading && (
            <div className="flex items-center gap-2 text-gray-400">
              <Loader2 className="w-5 h-5 animate-spin" />
              <span>Chargement...</span>
            </div>
          )}
          {!hasMore && animes.length > 0 && (
            <p className="text-gray-500 text-sm">{animes.length} animes affichés</p>
          )}
        </div>
      </div>
    </section>
  );
}

// Episode Button - Compact pill design
function EpisodeButton({ 
  episode, 
  selectedLang,
  onClick 
}: { 
  episode: Episode; 
  selectedLang: 'vf' | 'vostfr';
  onClick: () => void;
}) {
  const sources = selectedLang === 'vf' ? episode.sources.vf : episode.sources.vostfr;
  const hasSource = sources.length > 0;
  const uniqueSources = [...new Set(sources.map(s => s.source))];

  return (
    <motion.button
      onClick={() => hasSource && onClick()}
      disabled={!hasSource}
      whileHover={hasSource ? { scale: 1.05 } : {}}
      whileTap={hasSource ? { scale: 0.95 } : {}}
      className={`relative h-8 rounded-full text-xs font-medium transition-all duration-200 px-3 ${
        hasSource
          ? 'bg-white/5 hover:bg-purple-600/60 text-gray-300 hover:text-white border border-white/10 hover:border-purple-500/50'
          : 'bg-white/[0.02] text-gray-600 cursor-not-allowed border border-white/5'
      }`}
    >
      {episode.number}

      {/* Subtle multi-source indicator - tiny dot */}
      {uniqueSources.length > 1 && hasSource && (
        <span className="absolute -top-0.5 -right-0.5 w-2 h-2 rounded-full bg-emerald-500" />
      )}
    </motion.button>
  );
}

