  onWatchProgress,
}: {
  anime: Anime;
  onClose: () => void;
  onWatchProgress: (entry: Omit<WatchHistoryEntry, 'timestamp'>) => void;
}) {
  // Compute initial language based on available sources
  const hasVostfr = anime.seasons.some(s => 
    s.episodes.some(e => e.sources.vostfr.length > 0)
  );
  const hasVf = anime.seasons.some(s => 
    s.episodes.some(e => e.sources.vf.length > 0)
  );
  const initialLang = !hasVostfr && hasVf ? 'vf' : 'vostfr';

  const [selectedLang, setSelectedLang] = useState<'vf' | 'vostfr'>(initialLang);
  const [selectedSeason, setSelectedSeason] = useState<number>(0);
  const [currentVideo, setCurrentVideo] = useState<string | null>(null);
  const [currentEpisode, setCurrentEpisode] = useState<Episode | null>(null);
  const [availableSources, setAvailableSources] = useState<VideoSource[]>([]);
  const [activeSource, setActiveSource] = useState<VideoSource | null>(null);

  const currentSeason = anime.seasons[selectedSeason];

  const playEpisode = (episode: Episode) => {
    const sources = selectedLang === 'vf' ? episode.sources.vf : episode.sources.vostfr;
    if (sources.length > 0) {
      // Get unique sources sorted by priority (Sibnet first, Vidmoly last)
      const uniqueSources = getUniqueSources(sources);
      setAvailableSources(uniqueSources);
      setCurrentEpisode(episode);
      setCurrentVideo(uniqueSources[0].url);
      setActiveSource(uniqueSources[0]);

      // Save to watch history
      onWatchProgress({
        animeId: anime.id,
        animeSlug: anime.slug,
        animeTitle: anime.title,
        coverImage: anime.coverImage,
        type: anime.type,
        episodeNumber: episode.number,
        seasonNumber: currentSeason?.number || 1,
        language: selectedLang,
      });
    }
