              <div className="flex items-center gap-3">
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => { setCurrentVideo(null); setCurrentEpisode(null); }}
                  className="text-white bg-white/10 hover:bg-white/20 rounded-full h-8"
                >
                  <ChevronLeft className="w-4 h-4 mr-1" />
                  Retour
