              <div className="flex items-center gap-2">
                {/* Source Selector - Minimalist */}
                {availableSources.length > 1 && (
                  <div className="flex items-center gap-1 bg-black/40 backdrop-blur-sm rounded-full p-1">
                    {availableSources.map((src) => {
                      const config = SOURCE_CONFIG[src.source] || { color: 'text-gray-400', bg: 'bg-gray-500/30' };
                      return (
                        <button
                          key={src.id}
                          onClick={() => changeSource(src)}
