// Search Modal
function SearchModal({
  open,
  onClose,
  onAnimeSelect,
}: {
  open: boolean;
  onClose: () => void;
  onAnimeSelect: (anime: AnimeListItem) => void;
}) {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<AnimeListItem[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const searchAnimes = async () => {
      if (query.length < 2) {
        setResults([]);
        return;
      }

      setLoading(true);
      try {
        const res = await fetch(`/api/animes?search=${encodeURIComponent(query)}&limit=20`);
        const data = await res.json();
        if (data.success) {
          setResults(data.data.animes);
        }
      } catch (error) {
        console.error('Search error:', error);
      } finally {
        setLoading(false);
      }
    };

    const debounce = setTimeout(searchAnimes, 300);
    return () => clearTimeout(debounce);
  }, [query]);

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl bg-[#0a0a0f] border-white/10 text-white">
        <VisuallyHidden>
          <DialogTitle>Rechercher un anime</DialogTitle>
        </VisuallyHidden>
        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
          <Input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Rechercher un anime..."
            className="pl-12 h-14 bg-gray-900/50 border-white/10 focus:border-purple-500 text-white text-lg"
            autoFocus
          />
        </div>

        <div className="mt-4 max-h-[400px] overflow-y-auto">
          {loading && (
            <div className="flex items-center justify-center py-8">
              <Loader2 className="w-6 h-6 animate-spin text-purple-400" />
            </div>
          )}

          {!loading && results.length > 0 && (
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
              {results.map((anime, index) => (
                <AnimeCard
                  key={anime.id}
                  anime={anime}
                  onClick={() => {
                    onAnimeSelect(anime);
                    onClose();
                  }}
                  index={index}
                />
              ))}
            </div>
          )}

          {!loading && query.length >= 2 && results.length === 0 && (
            <div className="text-center py-8 text-gray-500">
              Aucun résultat pour "{query}"
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

// Main App
export default function FrivoxStreamApp() {
  const [currentPage, setCurrentPage] = useState<PageView>('home');
  const [selectedAnime, setSelectedAnime] = useState<Anime | null>(null);
  const [detailOpen, setDetailOpen] = useState(false);

  // Watch history
  const { history, addToHistory, removeFromHistory, clearHistory } = useWatchHistory();

  // Home data
  const [featuredAnimes, setFeaturedAnimes] = useState<AnimeListItem[]>([]);
  const [latestAnimes, setLatestAnimes] = useState<AnimeListItem[]>([]);
  const [popularAnimes, setPopularAnimes] = useState<AnimeListItem[]>([]);
  const [stats, setStats] = useState({ animes: 0, seasons: 0, episodes: 0, sources: 0 });

  // Catalog data
  const [catalogAnimes, setCatalogAnimes] = useState<AnimeListItem[]>([]);
  const [catalogPage, setCatalogPage] = useState(1);
  const [catalogTotal, setCatalogTotal] = useState(0);
  const [hasMore, setHasMore] = useState(true);
  const [loading, setLoading] = useState(false);

  // Fetch home data
  useEffect(() => {
    const fetchHomeData = async () => {
      try {
        const res = await fetch('/api/home');
        const data = await res.json();
        if (data.success) {
          setFeaturedAnimes(data.data.featured);
          setLatestAnimes(data.data.latestAnimes);
          setPopularAnimes(data.data.popular);
          setStats(data.data.stats);
        }
      } catch (error) {
        console.error('Error fetching home data:', error);
      }
    };

    if (currentPage === 'home') {
      fetchHomeData();
    }
  }, [currentPage]);

  // Fetch catalog data
  const loadCatalog = useCallback(async (page: number) => {
    setLoading(true);
    try {
      const res = await fetch(`/api/animes?page=${page}&limit=48`);
      const data = await res.json();
      if (data.success) {
        if (page === 1) {
          setCatalogAnimes(data.data.animes);
        } else {
          setCatalogAnimes(prev => [...prev, ...data.data.animes]);
        }
        setCatalogTotal(data.data.pagination.total);
        setHasMore(page < data.data.pagination.totalPages);
      }
    } catch (error) {
      console.error('Error loading catalog:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (currentPage === 'catalog' && catalogAnimes.length === 0) {
      loadCatalog(1);
    }
  }, [currentPage, catalogAnimes.length, loadCatalog]);

  const loadMore = useCallback(() => {
    if (!loading && hasMore) {
      const nextPage = catalogPage + 1;
      setCatalogPage(nextPage);
      loadCatalog(nextPage);
    }
  }, [loading, hasMore, catalogPage, loadCatalog]);

  // Fetch anime details when selected
  const handleAnimeClick = async (anime: AnimeListItem) => {
    try {
      const res = await fetch(`/api/animes/${anime.slug}`);
      const data = await res.json();
      if (data.success) {
        setSelectedAnime(data.data);
        setDetailOpen(true);
      }
    } catch (error) {
      console.error('Error fetching anime details:', error);
    }
  };

  // Handle click on history entry
  const handleHistoryClick = async (entry: WatchHistoryEntry) => {
    try {
      const res = await fetch(`/api/animes/${entry.animeSlug}`);
      const data = await res.json();
      if (data.success) {
        setSelectedAnime(data.data);
        setDetailOpen(true);
      }
    } catch (error) {
      console.error('Error fetching anime details:', error);
    }
  };

  return (
    <main className="min-h-screen flex flex-col">
      <AnimatedBackground />

      <Navigation
        currentPage={currentPage}
        onNavigate={setCurrentPage}
        onAnimeSelect={handleAnimeClick}
        total={stats.animes}
      />

      <div className="relative z-10 flex-1 pt-16 md:pt-20">
        {currentPage === 'home' ? (
          <>
            <HeroSection
              animes={featuredAnimes}
              onAnimeClick={handleAnimeClick}
            />

            {/* Continue Watching Section */}
            <ContinueWatchingSection
              history={history}
              onAnimeClick={handleHistoryClick}
              onRemove={removeFromHistory}
              onClear={clearHistory}
            />

            <SectionRow
              title="Récemment ajoutés"
              icon={TrendingUp}
              animes={latestAnimes}
              onAnimeClick={handleAnimeClick}
            />

            <SectionRow
              title="Les plus populaires"
              icon={Star}
              animes={popularAnimes}
              onAnimeClick={handleAnimeClick}
            />
          </>
        ) : (
          <CatalogPage
            animes={catalogAnimes}
            onAnimeClick={handleAnimeClick}
            hasMore={hasMore}
            loadMore={loadMore}
            loading={loading}
            total={catalogTotal}
          />
        )}
      </div>

      {/* Footer */}
      <footer className="relative z-10 mt-auto border-t border-white/5 bg-[#0a0a0f]/80 backdrop-blur-sm py-6">
        <div className="container mx-auto px-4 text-center">
          <div className="flex items-center justify-center gap-2 mb-2">
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-violet-600 to-pink-500 flex items-center justify-center">
              <span className="text-sm font-bold text-white">F</span>
            </div>
            <span className="text-lg font-bold text-white">FrivoxStream</span>
          </div>
          <p className="text-gray-500 text-sm">
            {stats.animes.toLocaleString()} animes • {stats.episodes.toLocaleString()} épisodes • {stats.sources.toLocaleString()} sources vidéo
          </p>
          <p className="text-gray-600 text-xs mt-2">
            © 2024 FrivoxStream. Tous droits réservés.
          </p>
        </div>
      </footer>

      {/* Modals */}
      <AnimeDetailModal
        anime={selectedAnime}
        open={detailOpen}
        onClose={() => {
          setDetailOpen(false);
          setSelectedAnime(null);
        }}
        onWatchProgress={addToHistory}
      />
    </main>
  );
}
